import React, { useState, useEffect, useCallback } from 'react';
import { getApiBase } from '../utils/platform';
import { tokens } from '../styles/tokens';
import s from './StrategyDecayPage.module.css';

const STATUS_CONFIG = {
  HEALTHY: { label: 'HEALTHY', bg: '#1a2e1a', border: tokens.color.green, color: tokens.color.green },
  WARN:    { label: 'WARN',    bg: '#2e2a1a', border: tokens.color.amber, color: tokens.color.amber },
  BRAKE:   { label: 'BRAKE',   bg: '#2e1a1a', border: tokens.color.red, color: tokens.color.red },
  DISABLE: { label: 'DISABLE', bg: '#2e1016', border: '#da3633', color: '#da3633' },
};

const COMPONENT_LABELS = {
  expectancy_drift: 'Expectancy Drift',
  regime_mismatch: 'Regime Mismatch',
  exec_deterioration: 'Exec Deterioration',
  stability: 'Stability',
  correlation: 'Correlation',
};

function scoreColor(score) {
  if (score >= 75) return tokens.color.red;
  if (score >= 50) return tokens.color.amber;
  if (score >= 25) return tokens.color.blue;
  return tokens.color.green;
}

function StatusBadge({ status }) {
  const cfg = STATUS_CONFIG[status] || STATUS_CONFIG.HEALTHY;
  return (
    <span className={s.statusBadge} style={{
      background: cfg.bg,
      border: `1px solid ${cfg.border}`,
      color: cfg.color,
    }}>
      {cfg.label}
    </span>
  );
}

function DecayBar({ value, color }) {
  return (
    <div className={s.decayBarTrack}>
      <div className={s.decayBarFill} style={{
        width: `${Math.min(100, Math.max(0, value))}%`,
        background: color || tokens.color.blue,
      }} />
    </div>
  );
}

function StrategyCard({ strategy }) {
  const { name, status, components, recommended_action } = strategy;
  const decay_score = Number(strategy.decay_score ?? 0);
  const sc = scoreColor(decay_score);

  return (
    <div className={s.strategyCard}>
      {/* Header */}
      <div className={s.cardHeader}>
        <span className={s.cardName}>{name}</span>
        <StatusBadge status={status} />
      </div>

      {/* Composite Score */}
      <div>
        <div className={s.compositeRow}>
          <span className={s.compositeLabel}>Composite Decay</span>
          <span className={s.compositeValue} style={{ color: sc }}>
            {decay_score.toFixed(1)}
          </span>
        </div>
        <DecayBar value={decay_score} color={sc} />
      </div>

      {/* Component Breakdown */}
      <div className={s.componentList}>
        {Object.entries(COMPONENT_LABELS).map(([key, label]) => {
          const val = Number(components?.[key] ?? 0);
          return (
            <div key={key}>
              <div className={s.componentRow}>
                <span className={s.componentLabel}>{label}</span>
                <span className={s.componentValue}>{val.toFixed(1)}</span>
              </div>
              <DecayBar value={val} color={scoreColor(val)} />
            </div>
          );
        })}
      </div>

      {/* Recommended Action */}
      {recommended_action && (
        <div className={s.actionBox}>{recommended_action}</div>
      )}
    </div>
  );
}

export default function StrategyDecayPage() {
  const [data, setData] = useState(null);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState(null);
  const [sortBy, setSortBy] = useState('score');

  const fetchData = useCallback(async () => {
    try {
      const res = await fetch(`${getApiBase()}/strategies/decay/summary`);
      if (!res.ok) throw new Error(`HTTP ${res.status}`);
      const json = await res.json();
      setData(json);
      setError(null);
    } catch (err) {
      setError(err.message);
    } finally {
      setLoading(false);
    }
  }, []);

  useEffect(() => {
    fetchData();
    const interval = setInterval(fetchData, 30000);
    return () => clearInterval(interval);
  }, [fetchData]);

  const sorted = data?.strategies?.slice().sort((a, b) => {
    if (sortBy === 'score') return (b.decay_score ?? 0) - (a.decay_score ?? 0);
    return (a.name || '').localeCompare(b.name || '');
  }) || [];

  const summary = data?.summary || {};

  const summaryItems = [
    { label: 'Total', value: summary.total ?? 0, color: tokens.color.text },
    { label: 'Healthy', value: summary.healthy ?? 0, color: tokens.color.green },
    { label: 'Warn', value: summary.warn ?? 0, color: tokens.color.amber },
    { label: 'Brake', value: summary.brake ?? 0, color: tokens.color.red },
    { label: 'Disable', value: summary.disable ?? 0, color: '#da3633' },
  ];

  return (
    <div className={s.page}>
      {/* Page Title */}
      <h1 className={s.title}>Strategy Decay Monitor</h1>

      {/* Summary Bar */}
      <div className={s.summaryBar}>
        {summaryItems.map(({ label, value, color }) => (
          <div key={label} className={s.summaryCard}>
            <span className={s.summaryValue} style={{ color }}>{value}</span>
            <span className={s.summaryLabel}>{label}</span>
          </div>
        ))}
      </div>

      {/* Sort Controls */}
      <div className={s.sortBar}>
        <span className={s.sortLabel}>Sort by:</span>
        {[
          { key: 'score', label: 'Decay Score (Worst First)' },
          { key: 'name', label: 'Name' },
        ].map(({ key, label }) => (
          <button
            key={key}
            onClick={() => setSortBy(key)}
            className={`${s.sortBtn} ${sortBy === key ? s.sortBtnActive : ''}`}
          >
            {label}
          </button>
        ))}
      </div>

      {/* Loading State */}
      {loading && (
        <div className={s.loadingState}>Loading decay data...</div>
      )}

      {/* Error State */}
      {error && !loading && (
        <div className={s.errorBanner}>Failed to load decay data: {error}</div>
      )}

      {/* Empty State */}
      {!loading && !error && sorted.length === 0 && (
        <div className={s.emptyState}>No strategy decay data available.</div>
      )}

      {/* Strategy Cards Grid */}
      {!loading && sorted.length > 0 && (
        <div className={s.cardsGrid}>
          {sorted.map((st) => (
            <StrategyCard key={st.name} strategy={st} />
          ))}
        </div>
      )}
    </div>
  );
}
